var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"이봐! 대체 어딜 가는 거야?","JPN":"もう、いったいどこ行くのよ！","ENG":"Hey! Where do you think you're going?","TWN":"喂！你到底要去哪啊？"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"STAR_PROMISE_NULL_NULL","text":{"KOREA":"와? 알면 따라오게?","JPN":"なんや？　教えたらついてくんのか？","ENG":"What? You're gonna follow me?","TWN":"什麼？想知道的話就跟上來？"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"당연하지! 난 아직 당신과 결판을 짓지 못했다고!","JPN":"当然でしょ！　私はまだあんたと決着をつけてないもの！","ENG":"Duh! I still have unfinished business with you!","TWN":"當然了！我還沒有和你決一勝負呢！"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"STAR_PROMISE_NULL_NULL","text":{"KOREA":"아하하, 참 오래도 가네. 내 덕에 나이트 잡고 랭커 된 건 잊었나?","JPN":"あはは、まだ引きずってるんやな。ウチのおかげでナイト倒してランカーになったの、忘れたんか？","ENG":"Ah hah hah, you're so stubborn. Did ya forget that you entered the top ranks because I helped ya defeat Knight?","TWN":"哈哈哈，真是難纏啊。難道忘了因為我打敗了騎士才能擠進前段班嗎？"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L9_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"아니거든! 내가 잘해서 여기까지 온 거거든?!","JPN":"違うわよ！　私が強いからここまで来たのよ！","ENG":"That's not true! I made it all the way here by myself!","TWN":"才不是呢！我是靠自己的本事爭取的！"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L10_1","type":"dialog","speaker":"STAR_PROMISE_NULL_NULL","text":{"KOREA":"진짜 성격 하고는, 아까 그 삼총사들이 대신 사과해 주지 않았으면 큰일났을 기다.","JPN":"ホンマ、ええ性格しとるな。さっきの3人が代わりに謝ってくれへんかったら、大事になっとったはずやで。","ENG":"Geez. If the trio didn't apologize for ya, you would've been toast.","TWN":"要不是剛才那三人組替你道歉，事情可就麻煩了。"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L11_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"필요 없어! 그깟 놈들이 뭐가 무섭다고!","JPN":"どうでもいいわ！　あんな奴ら怖くない！","ENG":"I didn't need to apologize! I'm not afraid of them!","TWN":"我不怕！那些傢伙有什麼好怕的！"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L12_1","type":"dialog","speaker":"STAR_PROMISE_NULL_NULL","text":{"KOREA":"……니는 아까 개들이랑 싸웠을 때 뭔가 못 느꼈나?","JPN":"……さっきあいつらと戦った時、おかしいと思わへんかったか？","ENG":"...Didn't ya feel something odd when you were fightin' them?","TWN":"……你剛才和那些傢伙戰鬥時，有沒有感覺到什麼？"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L13_1","type":"dialog","speaker":"STAR_PROMISE_NULL_NULL","text":{"KOREA":"아무리 아티팩트의 힘이라지만…… 너무 강하지 않았나?","JPN":"いくらアーティファクトの力借りてるとはいえ……強すぎたやろ？","ENG":"Even with the power of the Artifact... don't ya think it was a little too strong?","TWN":"雖然是神器的力量……但也太強了吧？"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"그, 그러고 보니…… 무슨 치트라도 쓴 것 같긴 했지……","JPN":"い、言われてみれば……チートでも使ったような感じだった……","ENG":"C-come to think of it... it did feel like they were cheating in a way...","TWN":"這，這麼說來……好像用了什麼作弊手法……"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"STAR_PROMISE_NULL_NULL","text":{"KOREA":"불안한 마음이 가시질 않네. 인자 놀 수만은 없겠다.","JPN":"この不安感……どうしても拭いきれへんねん。のんびりしてられんな。","ENG":"I can't seem to shake that feelin' off. Guess I can't just fool around like the ol' days anymore.","TWN":"不安的心情揮之不去，現在不能再悠閒下去了。"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"……예전부터 궁금했는데 말야, 당신 대체 뭐 하는 사람이야?","JPN":"……前から気になってたけど、あんたっていったい何者なの？","ENG":"...I've been meaning to ask, but who are you really?","TWN":"……我一直很好奇，你到底是做什麼的？"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"STAR_PROMISE_NULL_NULL","text":{"KOREA":"응? 그건 왜?","JPN":"ん？　なんで気になるん？","ENG":"Hmm? Why do ya wanna know?","TWN":"嗯？怎麼了？"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"처음 봤을 땐, 나랑 비슷한 나이라고 생각했어.","JPN":"初めて会った時は、私と同じぐらいの年齢だと思った。","ENG":"When I first saw you, I thought you were around my age.","TWN":"第一次見面時，我以為你和我年紀差不多。"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"근데 말투도 그렇고, 날 대하는 것도 무슨 어린애 대하듯이 하잖아.","JPN":"でも話す内容もそうだし、私のことも子ども扱いするし。","ENG":"But you talk to me and treat me as if I'm a child.","TWN":"但是你的語氣和對待我的態度，就像對待小孩子一樣。"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"빨리 말해. 당신 정체가 뭐야?","JPN":"早く明かしなさいよ。あんたの正体。","ENG":"So tell me. Who are you?","TWN":"快說，你到底是什麼人？"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"STAR_PROMISE_NULL_NULL","text":{"KOREA":"……듣고 싶나?","JPN":"……聞きたいんか？","ENG":"...Ya really wanna know?","TWN":"……想聽嗎？"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"STAR_PROMISE_NULL_NULL","text":{"KOREA":"후회…… 안 할 자신 있나?","JPN":"後悔せえへん自信ある？","ENG":"Are ya certain... ya won't regret it?","TWN":"你確定……不會後悔嗎？"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"이, 이런다고 내가 겁먹을 것 같아?!","JPN":"そ、そんなこと言ったら私が怯えるとでも思う？","ENG":"Y-you think that's going to scare me off?!","TWN":"你，你以為我會怕嗎？！"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"STAR_PROMISE_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L32_1","type":"dialog","speaker":"STAR_PROMISE_NULL_NULL","text":{"KOREA":"알았다. 그럼 따라온나.","JPN":"わかったわ。ほんならついて来いや。","ENG":"Aight. Follow me.","TWN":"知道了，那就跟上來吧。"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"무, 무슨 얘길 하려는 거지……?","JPN":"な、何を話すつもり……？","ENG":"W-what's she going to say...?","TWN":"你，你想說什麼……？"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CAMP_NIGHT","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"STAR_PROMISE_NULL_NULL","text":{"KOREA":"아하하! 그때는 진짜 깜짝 놀랐다 아이가!","JPN":"あはは！　あの時はほんまにびっくりしたで！","ENG":"Ah hah hah! It was a huge deal back then!","TWN":"哈哈哈！那時候真的嚇了一跳啊！"},"stage":{"bg":"CAMP_NIGHT","slots":{"L":null,"C":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"STAR_PROMISE_NULL_NULL","text":{"KOREA":"내가 장난으로 다인이 머리에다 술을 부운 적이 있었는데, 금마 그렇게 화난 모습은 내 처음 봤다!","JPN":"ふざけてタエの頭に酒かけたことあるけど、あいつがあんなに怒る姿は初めて見たわ！","ENG":"I poured alcohol on Dain's head as a joke, and it was the first time I ever saw her that angry!","TWN":"有一次我開玩笑把酒倒在了妲茵的頭上，那傢伙生氣的樣子我還是第一次見到！"},"stage":{"bg":"CAMP_NIGHT","slots":{"L":null,"C":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CAMP_NIGHT","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"STAR_PROMISE_NULL_NULL","text":{"KOREA":"그때 다인이가 뭐랬는지 아나?","JPN":"あの時、タエがなんて言うたと思う？","ENG":"Do ya know what she said to me?","TWN":"你知道那時候妲茵說了什麼嗎？"},"stage":{"bg":"CAMP_NIGHT","slots":{"L":null,"C":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};